#' Firth's Penalized Likelihood Regression
#'
#' Firth's penalized likelihood regression for both logistic (binary outcome) 
#' and Cox proportional hazards (survival) models. Addresses small-sample 
#' bias, complete/quasi-complete separation, and rare events by adding a 
#' Jeffreys-prior penalty to the likelihood. Provides profile likelihood 
#' confidence intervals, penalized likelihood ratio tests, and separation 
#' diagnostics. Particularly valuable in clinical settings with low event 
#' counts, unbalanced predictors, or when standard maximum likelihood 
#' estimates become infinite due to separation.
#' 
#'
#' @examples
#' \donttest{
#' # Firth logistic regression
#' firthregression(data = mydata, analysisType = "logistic",
#'     outcome = "mortality",
#'     predictors = c("age", "stage", "biomarker"))
#'
#' # Firth Cox regression
#' firthregression(data = mydata, analysisType = "cox",
#'     time = "follow_up_time", outcome = "status",
#'     predictors = c("age", "stage", "biomarker"))
#'}
#' @param data The data as a data frame.
#' @param analysisType Type of regression model. Logistic uses logistf package
#'   for binary outcomes with Jeffreys-prior bias reduction. Cox uses coxphf
#'   package for survival outcomes with Firth-type penalized partial likelihood.
#' @param time Time to event variable (numeric). Required only for Cox
#'   regression. For right-censored data, this is the time from study entry to
#'   event or censoring.
#' @param outcome Outcome variable. For logistic regression, a binary
#'   variable. For Cox regression, the event indicator (0 = censored, 1 =
#'   event).
#' @param outcomeLevel Level of the outcome variable to be treated as the
#'   event of interest.
#' @param predictors Variables to include in the model. Can include
#'   continuous, ordinal, and nominal variables.
#' @param suitabilityCheck Assess if data is suitable for the selected Firth
#'   regression model.
#' @param ciLevel Confidence level for confidence intervals. Default is 0.95
#'   for 95\% confidence intervals.
#' @param ciMethod Method for computing confidence intervals. Profile
#'   likelihood CIs are recommended as they are more accurate, especially with
#'   small samples and near separation. Wald CIs are faster but can be
#'   unreliable in these situations.
#' @param separationCheck Check for complete and quasi-complete separation in
#'   the data. Separation causes standard maximum likelihood to fail with
#'   infinite coefficient estimates.
#' @param compareStandard Fit the standard (unpenalized) model alongside
#'   Firth's penalized model to show bias reduction. Useful for assessing how
#'   much the penalty changes the estimates.
#' @param showModelFit Display model fit statistics including log-likelihood
#'   and AIC.
#' @param forestPlot Forest plot showing odds ratios (logistic) or hazard
#'   ratios (Cox) with confidence intervals on a log scale.
#' @param separationPlot Diagnostic visualization showing data distributions
#'   by outcome for each predictor. Helps identify separation patterns.
#' @param showSummary Natural-language summary of results.
#' @param showExplanations Explanatory text about Firth's method and when to
#'   use it.
#' @return A results object containing:
#' \tabular{llllll}{
#'   \code{results$instructions} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$notices} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$suitabilityReport} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$coefficients} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$modelFit} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$separationDiagnostics} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$comparisonTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$forestPlotImage} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$separationPlotImage} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$summaryText} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$explanationText} \tab \tab \tab \tab \tab a html \cr
#' }
#'
#' Tables can be converted to data frames with \code{asDF} or \code{\link{as.data.frame}}. For example:
#'
#' \code{results$coefficients$asDF}
#'
#' \code{as.data.frame(results$coefficients)}
#'
#' @export
firthregression <- function(
    data,
    analysisType = "logistic",
    time,
    outcome,
    outcomeLevel,
    predictors,
    suitabilityCheck = TRUE,
    ciLevel = 0.95,
    ciMethod = "profile",
    separationCheck = TRUE,
    compareStandard = TRUE,
    showModelFit = TRUE,
    forestPlot = TRUE,
    separationPlot = FALSE,
    showSummary = FALSE,
    showExplanations = FALSE) {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("firthregression requires jmvcore to be installed (restart may be required)")

    if ( ! missing(time)) time <- jmvcore::resolveQuo(jmvcore::enquo(time))
    if ( ! missing(outcome)) outcome <- jmvcore::resolveQuo(jmvcore::enquo(outcome))
    if ( ! missing(predictors)) predictors <- jmvcore::resolveQuo(jmvcore::enquo(predictors))
    if (missing(data))
        data <- jmvcore::marshalData(
            parent.frame(),
            `if`( ! missing(time), time, NULL),
            `if`( ! missing(outcome), outcome, NULL),
            `if`( ! missing(predictors), predictors, NULL))


    options <- firthregressionOptions$new(
        analysisType = analysisType,
        time = time,
        outcome = outcome,
        outcomeLevel = outcomeLevel,
        predictors = predictors,
        suitabilityCheck = suitabilityCheck,
        ciLevel = ciLevel,
        ciMethod = ciMethod,
        separationCheck = separationCheck,
        compareStandard = compareStandard,
        showModelFit = showModelFit,
        forestPlot = forestPlot,
        separationPlot = separationPlot,
        showSummary = showSummary,
        showExplanations = showExplanations)

    analysis <- firthregressionClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

